// Admin console shell + page router for insurance-claim-demo.
// Generated by flowforge JTBD generator — do not edit by hand.
import * as React from "react";

import { InstanceBrowser } from "./pages/InstanceBrowser";
import { AuditLogViewer } from "./pages/AuditLogViewer";
import { SagaPanel } from "./pages/SagaPanel";
import { PermissionsHistory } from "./pages/PermissionsHistory";
import { OutboxQueue } from "./pages/OutboxQueue";
import { RlsLog } from "./pages/RlsLog";
import { ADMIN_PERMISSIONS, type AdminPermission } from "./permissions";

type PageId =
	| "instances"
	| "audit"
	| "saga"
	| "grants"
	| "outbox"
	| "rls"
	;

interface PageDef {
	id: PageId;
	label: string;
	requires: ReadonlyArray<AdminPermission> | "any";
	render: () => React.ReactElement;
}

const PAGES: ReadonlyArray<PageDef> = [
	{
		id: "instances",
		label: "Instances",
		requires: "any",
		render: () => <InstanceBrowser />,
	},
	{
		id: "audit",
		label: "Audit log",
		requires: "any",
		render: () => <AuditLogViewer />,
	},
	{
		id: "saga",
		label: "Saga compensations",
		requires: ADMIN_PERMISSIONS.filter((p) => p.endsWith(".compensate")),
		render: () => <SagaPanel />,
	},
	{
		id: "grants",
		label: "Permission grants",
		requires: ADMIN_PERMISSIONS.filter((p) => p.endsWith(".grant")),
		render: () => <PermissionsHistory />,
	},
	{
		id: "outbox",
		label: "Outbox queue",
		requires: ADMIN_PERMISSIONS.filter((p) => p.endsWith(".outbox.retry")),
		render: () => <OutboxQueue />,
	},
	{
		id: "rls",
		label: "RLS elevations",
		requires: "any",
		render: () => <RlsLog />,
	},
];

export interface AppProps {
	/** Operator's granted permissions, supplied by the auth proxy. */
	grantedPermissions?: ReadonlyArray<AdminPermission>;
}

function isAllowed(
	page: PageDef,
	granted: ReadonlyArray<AdminPermission>,
): boolean {
	if (page.requires === "any") return granted.length > 0;
	return page.requires.some((p) => granted.includes(p));
}

export function App(props: AppProps): React.ReactElement {
	const granted = props.grantedPermissions ?? ADMIN_PERMISSIONS;
	const [active, setActive] = React.useState<PageId>("instances");

	const visiblePages = PAGES.filter((p) => isAllowed(p, granted));
	const current = visiblePages.find((p) => p.id === active) ?? visiblePages[0];

	return (
		<div className="ff-admin-app">
			<header className="ff-admin-header">
				<h1>insurance-claim-demo — admin console</h1>
				<p className="ff-admin-tenancy">tenancy: single</p>
			</header>
			<nav className="ff-admin-nav" aria-label="admin sections">
				<ul>
					{visiblePages.map((p) => (
						<li key={p.id}>
							<button
								type="button"
								aria-current={p.id === active ? "page" : undefined}
								onClick={() => setActive(p.id)}
							>
								{p.label}
							</button>
						</li>
					))}
				</ul>
			</nav>
			<main className="ff-admin-main">
				{current ? current.render() : <p>No admin permissions granted.</p>}
			</main>
		</div>
	);
}
